//! Compile-time and behavioral proof for `wasm4pm-compat-pack`'s generated
//! OCEL emission surface (`src/wasm4pm_compat_events.rs`).
//!
//! GENERATED by `wasm4pm-compat-pack` -- but unlike `events.rs.tmpl`/
//! `emission_boundary.md.tmpl`, this file carries NO `sparql:` frontmatter
//! and loops over NO ontology query for its per-variant expected literals.
//! Every expected `eventName`/`objectType` literal below was hand-
//! transcribed directly from `packs/wasm4pm-compat-pack/ontology.ttl`'s
//! three `w4pm:EventType` individuals, independently of the SPARQL
//! `event_types` query that generated the enum/emit-fns under test. Looping
//! that same query into this test's "expected" values too would make a
//! wrong `eventName`/`objectType` literal, or a broken `pascal_case`/
//! `snake_case` filter, corrupt the generated code and this test's
//! expectations identically -- the test could never catch it. Hardcoding
//! breaks that coupling.
//!
//! `EVENT_TYPE_COUNT`, however, IS a second, independent SPARQL-driven
//! oracle (the `event_count` query in `events.rs.tmpl`, a plain
//! `COUNT(DISTINCT ?et)` -- structurally unable to share a bug with the
//! `event_types` projection query that drives the enum/match arms, since it
//! selects no per-row fields at all). The cardinality assertion below
//! therefore self-updates on an ontology edit instead of requiring a human
//! to bump a literal `3`.

#[path = "../src/wasm4pm_compat_events.rs"]
mod wasm4pm_compat_events;

use chrono::DateTime;
use wasm4pm_compat::ocel::{OCELAttributeValue, OCELEvent, OCELEventAttribute, OCELRelationship};
use wasm4pm_compat_events::{EmittedEventType, EVENT_TYPE_COUNT};

fn literal_time() -> chrono::DateTime<chrono::FixedOffset> {
    DateTime::parse_from_rfc3339("2026-07-17T00:00:00+00:00")
        .expect("literal RFC 3339 timestamp must parse")
}

/// Independent-oracle cardinality proof: `EVENT_TYPE_COUNT` comes from a
/// SPARQL query (`event_count`) that shares no projected variable with the
/// `event_types` query driving the enum below, so a bug in one cannot hide
/// a bug in the other. This is the "second, independent SPARQL-driven
/// oracle" the maturity audit's gap analysis asked for -- narrower than
/// literal-name derivation (which would defeat this test's whole purpose,
/// see module doc), but the cardinality check no longer requires a human to
/// remember to bump a hand-written `3`.
#[test]
fn event_type_count_matches_independent_sparql_oracle() {
    assert_eq!(EVENT_TYPE_COUNT, 3);
}

/// Structural proof: an exhaustive match with NO wildcard arm. If a future
/// ontology edit adds, removes, or renames a `w4pm:EventType` individual,
/// `events.rs.tmpl` regenerates a differently-shaped `EmittedEventType` enum
/// and this `match` fails to compile until this test is updated to match --
/// an independent (non-SPARQL) proof of exact cardinality: exactly the 3
/// individuals currently in the ontology (`GraphUnionHashed`,
/// `PackLockVerified`, `ReceiptChained`), no more, no fewer.
#[test]
fn emitted_event_type_has_exactly_the_three_ontology_variants() {
    let all = [
        EmittedEventType::GraphUnionHashed,
        EmittedEventType::PackLockVerified,
        EmittedEventType::ReceiptChained,
    ];
    assert_eq!(all.len(), EVENT_TYPE_COUNT);
    for variant in all {
        let expected_name = match variant {
            EmittedEventType::GraphUnionHashed => "graph_union_hashed",
            EmittedEventType::PackLockVerified => "pack_lock_verified",
            EmittedEventType::ReceiptChained => "receipt_chained",
        };
        assert_eq!(variant.name(), expected_name);
    }
}

/// Direct literal check of `EmittedEventType::name()` against the
/// `w4pm:eventName` values transcribed from `ontology.ttl`.
#[test]
fn emitted_event_type_name_matches_ontology_event_name_literals() {
    assert_eq!(
        EmittedEventType::GraphUnionHashed.name(),
        "graph_union_hashed"
    );
    assert_eq!(
        EmittedEventType::PackLockVerified.name(),
        "pack_lock_verified"
    );
    assert_eq!(EmittedEventType::ReceiptChained.name(), "receipt_chained");
}

/// Behavioral proof: call the real generated `emit_graph_union_hashed` with
/// concrete literal inputs and assert on the concrete literal fields of the
/// real `OCELEvent` it returns, INCLUDING the ontology-declared `graph_hash`
/// attribute (`w4pm:hasAttribute` on `w4pm:GraphUnionHashed`) -- no longer
/// an always-empty `Vec::new()`. `w4pm:GraphUnionHashed`'s
/// `w4pm:hasObjectType` is `w4pm:OntologyGraph`.
#[test]
fn emit_graph_union_hashed_binds_ontology_graph_relationship_and_attribute() {
    let event = wasm4pm_compat_events::emit_graph_union_hashed(
        "evt-1".to_string(),
        literal_time(),
        "graph-abc".to_string(),
        "hash-of-graph".to_string(),
    );

    assert_eq!(event.id, "evt-1");
    assert_eq!(event.event_type, "graph_union_hashed");
    assert_eq!(event.attributes.len(), 1);
    assert_eq!(
        event.attributes[0],
        OCELEventAttribute {
            name: "graph_hash".to_string(),
            value: OCELAttributeValue::String("hash-of-graph".to_string()),
        }
    );
    assert_eq!(event.relationships.len(), 1);
    assert_eq!(
        event.relationships[0],
        OCELRelationship {
            object_id: "graph-abc".to_string(),
            qualifier: "OntologyGraph".to_string(),
        }
    );
}

