/// New coverage `events.rs.tmpl`'s own output never exercises: `OCELEvent`
/// is `Serialize`/`Deserialize` (`wasm4pm_compat::ocel`, pinned dependency
/// `=26.6.29` -- `event_type` renames to JSON key `"type"`,
/// `OCELRelationship::object_id` renames to JSON key `"objectId"`). Round-
/// trip one emitted event (now carrying a real, ontology-declared
/// attribute) through JSON and assert on literal substrings plus struct
/// equality after deserialization.
#[test]
fn emitted_pack_lock_verified_event_round_trips_through_json() {
    let event = wasm4pm_compat_events::emit_pack_lock_verified(
        "evt-4".to_string(),
        literal_time(),
        "pack-99".to_string(),
        "hash-of-pack".to_string(),
    );

    let json = serde_json::to_string(&event).expect("OCELEvent must serialize");
    assert!(json.contains("\"type\":\"pack_lock_verified\""));
    assert!(json.contains("\"objectId\":\"pack-99\""));
    assert!(json.contains("\"qualifier\":\"Pack\""));
    assert!(json.contains("\"pack_hash\""));
    assert!(json.contains("\"hash-of-pack\""));

    let round_tripped: OCELEvent =
        serde_json::from_str(&json).expect("OCELEvent must deserialize");
    assert_eq!(round_tripped, event);
}

/// Real error/failure-path proof: `ontology.ttl` now declares
/// `w4pm:requiresNonEmptyId true` on every `w4pm:EventType`, and
/// `events.rs.tmpl` compiles that precondition into a real `debug_assert!`
/// inside each generated `emit_*` fn (not just a doc comment). This test
/// drives that failure path directly -- an empty `id` must panic in a debug
/// build (the build profile `cargo test` uses), closing part of the "a real
/// failure/error path per emitted event" gap named in the maturity audit's
/// test-generation notes for this pack. Runs `#[cfg(debug_assertions)]`
/// only, since `debug_assert!` is compiled out entirely in release builds
/// by design -- asserting a panic in that profile would misrepresent what
/// the generated code actually does.
#[test]
#[cfg(debug_assertions)]
#[should_panic(expected = "w4pm:requiresNonEmptyId")]
fn emit_graph_union_hashed_panics_on_empty_id() {
    let _ = wasm4pm_compat_events::emit_graph_union_hashed(
        String::new(),
        literal_time(),
        "graph-abc".to_string(),
        "hash-of-graph".to_string(),
    );
}

